163	// MarshalJSON provides optimized JSON encoding for CheckpointMetrics.
164	//
165	// Since schema.Float has custom MarshalJSON, serializing []Float has significant overhead.
166	// This method manually constructs JSON to avoid allocations and interface conversions.
167	func (cm *CheckpointMetrics) MarshalJSON() ([]byte, error) {
168		buf := make([]byte, 0, 128+len(cm.Data)*8)
169		buf = append(buf, `{"frequency":`...)
170		buf = strconv.AppendInt(buf, cm.Frequency, 10)
171		buf = append(buf, `,"start":`...)
172		buf = strconv.AppendInt(buf, cm.Start, 10)
173		buf = append(buf, `,"data":[`...)
174		for i, x := range cm.Data {
175			if i != 0 {
176				buf = append(buf, ',')
177			}
178			if x.IsNaN() {
179				buf = append(buf, `null`...)
180			} else {
181				buf = strconv.AppendFloat(buf, float64(x), 'f', 1, 32)
182			}
183		}
184		buf = append(buf, `]}`...)
185		return buf, nil
186	}
