188	// ToCheckpoint writes metric data to checkpoint files in parallel (JSON format).
189	//
190	// Metrics at root and cluster levels are skipped. One file per host is created.
191	// Uses worker pool (Keys.NumWorkers) for parallel processing. Only locks one host
192	// at a time, allowing concurrent writes/reads to other hosts.
193	//
194	// Returns the number of checkpoint files created and any errors encountered.
195	func (m *MemoryStore) ToCheckpoint(dir string, from, to int64) (int, error) {
196		// Pre-calculate capacity by counting cluster/host pairs
197		m.root.lock.RLock()
198		totalHosts := 0
199		for _, l1 := range m.root.children {
200			l1.lock.RLock()
201			totalHosts += len(l1.children)
202			l1.lock.RUnlock()
203		}
204		m.root.lock.RUnlock()
205	
206		levels := make([]*Level, 0, totalHosts)
207		selectors := make([][]string, 0, totalHosts)
208	
209		m.root.lock.RLock()
210		for sel1, l1 := range m.root.children {
211			l1.lock.RLock()
212			for sel2, l2 := range l1.children {
213				levels = append(levels, l2)
214				selectors = append(selectors, []string{sel1, sel2})
215			}
216			l1.lock.RUnlock()
217		}
218		m.root.lock.RUnlock()
219	
220		type workItem struct {
221			level    *Level
222			dir      string
223			selector []string
224		}
225	
226		n, errs := int32(0), int32(0)
227	
228		var wg sync.WaitGroup
229		wg.Add(Keys.NumWorkers)
230		work := make(chan workItem, Keys.NumWorkers*2)
231		for worker := 0; worker < Keys.NumWorkers; worker++ {
232			go func() {
233				defer wg.Done()
234	
235				for workItem := range work {
236					if err := workItem.level.toCheckpoint(workItem.dir, from, to, m); err != nil {
237						if err == ErrNoNewArchiveData {
238							continue
239						}
240	
241						cclog.Errorf("[METRICSTORE]> error while checkpointing %#v: %s", workItem.selector, err.Error())
242						atomic.AddInt32(&errs, 1)
243					} else {
244						atomic.AddInt32(&n, 1)
245					}
246				}
247			}()
248		}
249	
250		for i := 0; i < len(levels); i++ {
251			dir := path.Join(dir, path.Join(selectors[i]...))
252			work <- workItem{
253				level:    levels[i],
254				dir:      dir,
255				selector: selectors[i],
256			}
257		}
258	
259		close(work)
260		wg.Wait()
261	
262		if errs > 0 {
263			return int(n), fmt.Errorf("[METRICSTORE]> %d errors happened while creating checkpoints (%d successes)", errs, n)
264		}
265		return int(n), nil
266	}
