268	// toCheckpointFile recursively converts a Level tree to CheckpointFile structure.
269	// Skips metrics that are already archived. Returns nil if no unarchived data exists.
270	func (l *Level) toCheckpointFile(from, to int64, m *MemoryStore) (*CheckpointFile, error) {
271		l.lock.RLock()
272		defer l.lock.RUnlock()
273	
274		retval := &CheckpointFile{
275			From:     from,
276			To:       to,
277			Metrics:  make(map[string]*CheckpointMetrics),
278			Children: make(map[string]*CheckpointFile),
279		}
280	
281		for metric, minfo := range m.Metrics {
282			b := l.metrics[minfo.offset]
283			if b == nil {
284				continue
285			}
286	
287			allArchived := true
288			b.iterFromTo(from, to, func(b *buffer) error {
289				if !b.archived {
290					allArchived = false
291					return fmt.Errorf("stop") // Early termination signal
292				}
293				return nil
294			})
295	
296			if allArchived {
297				continue
298			}
299	
300			data := make([]schema.Float, (to-from)/b.frequency+1)
301			data, start, end, err := b.read(from, to, data)
302			if err != nil {
303				return nil, err
304			}
305	
306			for i := int((end - start) / b.frequency); i < len(data); i++ {
307				data[i] = schema.NaN
308			}
309	
310			retval.Metrics[metric] = &CheckpointMetrics{
311				Frequency: b.frequency,
312				Start:     start,
313				Data:      data,
314			}
315		}
316	
317		for name, child := range l.children {
318			val, err := child.toCheckpointFile(from, to, m)
319			if err != nil {
320				return nil, err
321			}
322	
323			if val != nil {
324				retval.Children[name] = val
325			}
326		}
327	
328		if len(retval.Children) == 0 && len(retval.Metrics) == 0 {
329			return nil, nil
330		}
331	
332		return retval, nil
333	}
