398	// FromCheckpoint loads checkpoint files from disk into memory in parallel.
399	//
400	// Uses worker pool to load cluster/host combinations. Returns number of files
401	// loaded and any errors.
402	func (m *MemoryStore) FromCheckpoint(dir string, from int64) (int, error) {
403		var wg sync.WaitGroup
404		work := make(chan [2]string, Keys.NumWorkers*4)
405		n, errs := int32(0), int32(0)
406	
407		wg.Add(Keys.NumWorkers)
408		for worker := 0; worker < Keys.NumWorkers; worker++ {
409			go func() {
410				defer wg.Done()
411				for host := range work {
412					lvl := m.root.findLevelOrCreate(host[:], len(m.Metrics))
413					nn, err := lvl.fromCheckpoint(m, filepath.Join(dir, host[0], host[1]), from)
414					if err != nil {
415						cclog.Errorf("[METRICSTORE]> error while loading checkpoints for %s/%s: %s", host[0], host[1], err.Error())
416						atomic.AddInt32(&errs, 1)
417					}
418					atomic.AddInt32(&n, int32(nn))
419				}
420			}()
421		}
422	
423		err := enqueueCheckpointHosts(dir, work)
424		close(work)
425		wg.Wait()
426	
427		if err != nil {
428			return int(n), err
429		}
430	
431		if errs > 0 {
432			return int(n), fmt.Errorf("[METRICSTORE]> %d errors happened while creating checkpoints (%d successes)", errs, n)
433		}
434		return int(n), nil
435	}
