437	// FromCheckpointFiles is the main entry point for loading checkpoints at startup.
438	//
439	// Creates checkpoint directory if it doesn't exist. This function must be called
440	// before any writes or reads, and can only be called once.
441	func (m *MemoryStore) FromCheckpointFiles(dir string, from int64) (int, error) {
442		if _, err := os.Stat(dir); os.IsNotExist(err) {
443			err := os.MkdirAll(dir, CheckpointDirPerms)
444			if err != nil {
445				cclog.Fatalf("[METRICSTORE]> Error creating directory: %#v\n", err)
446			}
447			cclog.Debugf("[METRICSTORE]> %#v Directory created successfully", dir)
448		}
449	
450		return m.FromCheckpoint(dir, from)
451	}
