453	func (l *Level) loadJSONFile(m *MemoryStore, f *os.File, from int64) error {
454		br := bufio.NewReader(f)
455		cf := &CheckpointFile{}
456		if err := json.NewDecoder(br).Decode(cf); err != nil {
457			return err
458		}
459	
460		if cf.To != 0 && cf.To < from {
461			return nil
462		}
463	
464		if err := l.loadFile(cf, m); err != nil {
465			return err
466		}
467	
468		return nil
469	}
470	
471	func (l *Level) loadFile(cf *CheckpointFile, m *MemoryStore) error {
472		for name, metric := range cf.Metrics {
473			n := len(metric.Data)
474			b := &buffer{
475				frequency: metric.Frequency,
476				start:     metric.Start,
477				data:      metric.Data[0:n:n],
478				prev:      nil,
479				next:      nil,
480				archived:  true,
481			}
482	
483			minfo, ok := m.Metrics[name]
484			if !ok {
485				continue
486			}
487	
488			prev := l.metrics[minfo.offset]
489			if prev == nil {
490				l.metrics[minfo.offset] = b
491			} else {
492				if prev.start > b.start {
493					return fmt.Errorf("[METRICSTORE]> buffer start time %d is before previous buffer start %d", b.start, prev.start)
494				}
495	
496				b.prev = prev
497				prev.next = b
498			}
499			l.metrics[minfo.offset] = b
500		}
501	
502		if len(cf.Children) > 0 && l.children == nil {
503			l.children = make(map[string]*Level)
504		}
505	
506		for sel, childCf := range cf.Children {
507			child, ok := l.children[sel]
508			if !ok {
509				child = &Level{
510					metrics:  make([]*buffer, len(m.Metrics)),
511					children: nil,
512				}
513				l.children[sel] = child
514			}
515	
516			if err := child.loadFile(childCf, m); err != nil {
517				return err
518			}
519		}
520	
521		return nil
522	}
